import{_ as a,o,c as r,j as e,a as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"5. Letter Of Offer","description":"","frontmatter":{"title":"5. Letter Of Offer","eba":"Allied Health Professionals 2021-2026","topics":["appendices","employment","forms"]},"headers":[],"relativePath":"ebas/allied-health/appendices/5-letter-of-offer.md","filePath":"ebas/allied-health/appendices/5-letter-of-offer.md"}'),i={name:"ebas/allied-health/appendices/5-letter-of-offer.md"};function l(s,t,f,d,h,m){return o(),r("div",null,[...t[0]||(t[0]=[e("h1",{id:"_5-letter-of-offer",tabindex:"-1"},[n("5. Letter Of Offer "),e("a",{class:"header-anchor",href:"#_5-letter-of-offer","aria-label":'Permalink to "5. Letter Of Offer"'},"​")],-1),e("p",null,"Formatting note",-1),e("p",null,"The appendix body below is rendered in a monospaced block to preserve the column layout of pay tables and forms. The block is excluded from the search index so search results stay short; find appendices by their title, number, topic or synonyms.",-1),e("p",null,[e("code",null,"text The letter of offer will include the following information: 1. the name of the Employer; 2. the Employee's classification, increment and job title; 3. the location/s where the Employee is to be situated; 4. the Employee’s mode of employment (whether full-time, part-time, fixed term or casual etc); 5. the name of this Agreement, which contains the Employee’s terms and conditions of employment; 6. the Employee’s fortnightly hours (full or part-time Employees) and that additional ordinary time shifts may be worked by a part-time Employee by mutual agreement with the Employer; 7. that shifts will be worked in accordance with a roster; 8. for part-time Employees: a. the agreed upon: i. regular pattern of work, specifying at least the hours worked each day; ii. which days of the week the Employee will work; iii. the actual starting and finishing times each day; b. that payment of additional shifts will not be at casual rates; and c. that any variation to the regular pattern of work must be by agreement between the Employer and the Employee and will be recorded in writing; 9. a statement to the effect that employment is ongoing unless a genuine fixed term appointment is proposed, and, where a genuine fixed term is proposed, the reason the role is genuine fixed term employment, the duration of the fixed term and the rights of an incumbent Employee (if relevant); 10. the date of commencement; 11. acknowledgment and details (where applicable) of prior service/entitlements to personal leave, long service etc.; 12. relevant allowances payable; and 13. other information as required depending on the nature of the position.")],-1)])])}const y=a(i,[["render",l]]);export{c as __pageData,y as default};
